#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define PI 3.14159265358979323846
#define MAX_N 50

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    if (x[1] == y[1])
        return x[0] - y[0];
    return x[1] - y[1];
}

double calculate_area(int *x, int *y, int n) {
    double area = 0.0;
    for (int i = 0; i < n; i++) {
        int j = (i + 1) % n;
        area += (x[i] * y[j] - x[j] * y[i]);
    }
    return fabs(area) / 2.0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int x[MAX_N], y[MAX_N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &x[i], &y[i]);
        }
        double max_area = 0.0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                int temp_x[MAX_N], temp_y[MAX_N];
                int temp_n = 0;
                for (int k = 0; k < N; k++) {
                    if (k != i && k != j) {
                        temp_x[temp_n] = x[k];
                        temp_y[temp_n] = y[k];
                        temp_n++;
                    }
                }
                double area = calculate_area(temp_x, temp_y, temp_n);
                if (area > max_area) {
                    max_area = area;
                }
            }
        }
        printf("%.1f\n", max_area);
    }
    return 0;
}

