#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
using namespace std;

double calculate_area(vector<int> x, vector<int> y) {
    double area = 0.0;
    for (int i = 0; i < x.size(); i++) {
        int j = (i + 1) % x.size();
        area += (x[i] * y[j] - x[j] * y[i]);
    }
    return fabs(area) / 2.0;
}

int main() {
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        vector<int> x(N), y(N);
        for (int i = 0; i < N; i++) {
            cin >> x[i] >> y[i];
        }
        double max_area = 0.0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                vector<int> temp_x, temp_y;
                for (int k = 0; k < N; k++) {
                    if (k != i && k != j) {
                        temp_x.push_back(x[k]);
                        temp_y.push_back(y[k]);
                    }
                }
                double area = calculate_area(temp_x, temp_y);
                if (area > max_area) {
                    max_area = area;
                }
            }
        }
        cout << fixed << setprecision(1) << max_area << endl;
    }
    return 0;
}

