import java.util.Scanner;
public class Main {
    public static double calculate_area(int[] x, int[] y) {
        double area = 0.0;
        for (int i = 0; i < x.length; i++) {
            int j = (i + 1) % x.length;
            area += (x[i] * y[j] - x[j] * y[i]);
        }
        return Math.abs(area) / 2.0;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int[] x = new int[N], y = new int[N];
            for (int i = 0; i < N; i++) {
                x[i] = scanner.nextInt();
                y[i] = scanner.nextInt();
            }
            double max_area = 0.0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    int[] temp_x = new int[N - 2], temp_y = new int[N - 2];
                    int temp_n = 0;
                    for (int k = 0; k < N; k++) {
                        if (k != i && k != j) {
                            temp_x[temp_n] = x[k];
                            temp_y[temp_n] = y[k];
                            temp_n++;
                        }
                    }
                    double area = calculate_area(temp_x, temp_y);
                    if (area > max_area) {
                        max_area = area;
                    }
                }
            }
