import math

def calculate_area(x, y):
    area = 0.0
    for i in range(len(x)):
        j = (i + 1) % len(x)
        area += (x[i] * y[j] - x[j] * y[i])
    return abs(area) / 2.0

def main():
    T = int(input())
    while T > 0:
        N = int(input())
        x = [0] * N
        y = [0] * N
        for i in range(N):
            x[i], y[i] = map(int, input().split())
        max_area = 0.0
        for i in range(N):
            for j in range(i + 1, N):
                temp_x = [x[k] for k in range(N) if k != i and k != j]
                temp_y = [y[k] for k in range(N) if k != i and k != j]
                area = calculate_area(temp_x, temp_y)
                if area > max_area:
                    max_area = area
        print(f"{max_area:.1f}")
        T -= 1

def solve():
    main()
